<script setup lang="ts">
import {computed,onMounted,ref} from 'vue';import {AlertTriangle,CheckCircle2,Quote,RefreshCw,Search,Target,Wrench} from 'lucide-vue-next';import KpiCard from '../components/common/KpiCard.vue';import BaseChart from '../components/charts/BaseChart.vue';import StatusBadge from '../components/common/StatusBadge.vue';import {evalApi} from '../api/eval';const metrics=ref<any>(null),cases=ref<any[]>([]),results=ref<any[]>([]),running=ref(false);onMounted(async()=>{[metrics.value,cases.value,results.value]=await Promise.all([evalApi.metrics(),evalApi.cases(),evalApi.results()])});const option=computed(()=>({tooltip:{trigger:'axis'},legend:{top:0},grid:{left:42,right:45,top:38,bottom:28},xAxis:{type:'category',data:metrics.value?.trend.map((x:any)=>x.date)||[]},yAxis:[{type:'value',min:80,max:100},{type:'value',min:0,max:10}],series:[{name:'数据准确率',type:'line',smooth:true,data:metrics.value?.trend.map((x:any)=>x.data_accuracy)||[],symbol:'none'},{name:'检索命中率',type:'line',smooth:true,data:metrics.value?.trend.map((x:any)=>x.retrieval_hit_rate)||[],symbol:'none'},{name:'幻觉率',type:'line',smooth:true,yAxisIndex:1,data:metrics.value?.trend.map((x:any)=>x.hallucination_rate)||[],symbol:'none',lineStyle:{color:'#ef4444',type:'dashed'}}]}));function run(){running.value=true;setTimeout(()=>running.value=false,1000)}
</script>
<template><div v-if="metrics"><div class="page-actions"><button class="btn primary" @click="run"><RefreshCw :size="16"/>{{running?'评估中...':'新建评估任务'}}</button></div><div class="kpi-grid six grid"><KpiCard label="数据准确率" :value="metrics.data_accuracy+'%'" change="+2.31pp" tone="blue" :icon="Target"/><KpiCard label="检索命中率" :value="metrics.retrieval_hit_rate+'%'" change="+1.87pp" tone="green" :icon="Search"/><KpiCard label="引用覆盖率" :value="metrics.citation_coverage+'%'" change="+2.06pp" tone="purple" :icon="Quote"/><KpiCard label="工具成功率" :value="metrics.tool_success_rate+'%'" change="+3.41pp" tone="orange" :icon="Wrench"/><KpiCard label="幻觉率" :value="metrics.hallucination_rate+'%'" change="-0.64pp" tone="red" :icon="AlertTriangle"/><KpiCard label="任务恢复率" :value="metrics.task_recovery_rate+'%'" change="+1.23pp" tone="green" :icon="CheckCircle2"/></div><div class="split-main"><section class="grid"><article class="panel chart-panel"><div class="panel-title"><h2>评估趋势（近30天）</h2></div><div class="panel-body"><BaseChart :option="option" :height="280"/></div></article><article class="panel"><div class="panel-title"><h2>最近评估用例</h2></div><div class="table-wrap"><table><thead><tr><th>用例ID</th><th>任务 / 场景</th><th>技能</th><th>综合得分</th><th>状态</th></tr></thead><tbody><tr v-for="(x,i) in cases" :key="x.id"><td>{{x.case_id}}</td><td><b>{{x.name}}</b></td><td>{{x.skill_name}}</td><td>{{results[i]?.score||94}}</td><td><StatusBadge :text="(results[i]?.status||'passed')==='passed'?'通过':'需复核'" :tone="(results[i]?.status||'passed')==='passed'?'success':'warning'"/></td></tr><tr v-for="i in 4" :key="i"><td>CASE-20240520-0{{i+10}}</td><td>Mock 财报分析完整性评估</td><td>evidence_coverage_check</td><td>{{90+i}}</td><td><StatusBadge text="通过" tone="success"/></td></tr></tbody></table></div></article></section><aside class="grid"><article class="panel"><div class="panel-title"><h2>失败用例分析（近7天）</h2></div><div class="panel-body"><div v-for="x in [{t:'引用不足',s:58},{t:'财报期间映射错误',s:62},{t:'工具调用超时',s:59}]" :key="x.t" style="padding:12px 0;border-bottom:1px solid var(--color-border)"><StatusBadge text="失败" tone="danger"/><b style="display:block;margin:8px 0">{{x.t}}</b><span class="muted">综合得分：{{x.s}}</span></div></div></article><article class="panel"><div class="panel-title"><h2>下一步行动建议</h2></div><ul class="timeline"><li>补充证据映射和引用模板</li><li>优化财报期间识别规则</li><li>为 MCP 调用增加重试与降级</li></ul></article></aside></div></div><div v-else class="empty">正在加载评估指标...</div></template>
